// KI-Ergebnisse parsen – Anthropic API Format: content[0].text
const input = $input.first().json;
let kiAntwort;

const raw = input.content?.[0]?.text
  || input.text
  || input.output
  || JSON.stringify(input);

try {
  if (typeof raw === 'string') {
    const m = raw.match(/\{[\s\S]*\}/);
    kiAntwort = m ? JSON.parse(m[0]) : JSON.parse(raw);
  } else {
    kiAntwort = raw;
  }
} catch (e) {
  console.log('⚠️ JSON-Parse fehlgeschlagen');
  kiAntwort = {
    datum: new Date().toISOString().split('T')[0],
    fehler: 'KI-Antwort nicht parsbar',
    rohdaten: String(raw).substring(0, 5000)
  };
}

console.log(`📰 ${kiAntwort.nachrichten?.length || 0} Nachrichten, ${kiAntwort.trends?.length || 0} Trends`);

return [{ json: {
  status: 'ok',
  datum: kiAntwort.datum || new Date().toISOString().split('T')[0],
  nachrichtenAnzahl: kiAntwort.nachrichten?.length || 0,
  trendsAnzahl: kiAntwort.trends?.length || 0,
  nachrichten: kiAntwort.nachrichten || [],
  trends: kiAntwort.trends || [],
  erstelltAm: new Date().toISOString()
}}];
